Sentry.init({
  dsn: process.env.SENTRY_DSN,
  environment: process.env.NODE_ENV,
  tracesSampleRate: 1.0,

  // Alert on high error rates
  beforeSend(event, hint) {
    // Filter out expected errors
    if (event.exception?.values?.[0]?.type === 'NotFound') {
      return null
    }
    return event
  },
})

